B.HD=new A.lk("1.0.0.b14","1.0.0.b14 c\u1eadp nh\u1eadt linh s\u1ee7ng, qu\xe0 t\u1eb7ng v\xe0 t\u1ed1i \u01b0u giao di\u1ec7n.","B\u1ea3n n\xe0y m\u1edf r\u1ed9ng h\u1ec7 th\u1ed1ng pet theo h\u01b0\u1edbng d\u1ec5 d\xf9ng h\u01a1n, b\u1ed5 sung n\u1ed9i dung qu\xe0 t\u1eb7ng v\xe0 tinh g\u1ecdn tr\u1ea3i nghi\u1ec7m \u1edf m\xe0n h\xecnh ch\xednh v\xe0 chi\u1ebfn \u0111\u1ea5u.",B.a25)
B.a_t=s(["B\u1ea3ng s\u1ef1 ki\u1ec7n \u0111\u01b0\u1ee3c m\u1edf trong c\u1eeda s\u1ed5 ri\xeang khi b\u1ea5m v\xe0o khung S\u1ef1 ki\u1ec7n \u1edf trang ch\u1ee7.","Th\u1eafng tr\u1eadn s\u1ebd c\xf3 c\u01a1 h\u1ed9i nh\u1eadn l\u01b0\u1ee3t m\u1edf: \u0111\u1ed1i th\u1ee7 c\xe0ng ngang c\u1ea5p ho\u1eb7c cao c\u1ea5p th\xec c\u01a1 h\u1ed9i c\xe0ng cao.","M\u1edf tr\xfang ph\u1ea7n th\u01b0\u1edfng s\u1ebd hi\u1ec7n th\xf4ng b\xe1o ngay \u0111\u1ec3 b\u1ea1n bi\u1ebft v\u1eeba nh\u1eadn \u0111\u01b0\u1ee3c g\xec.","Trong b\u1ea3ng s\u1ef1 ki\u1ec7n c\xf3 ph\u1ea7n m\xf4 t\u1ea3 t\u1ef7 l\u1ec7 nh\u1eadn l\u01b0\u1ee3t m\u1edf \u0111\u1ec3 d\u1ec5 theo d\xf5i."],t.s)
