B.a2u=s(["D\xf9ng {item} c\u0169ng ch\u1ec9 c\xe2u gi\u1edd th\xf4i.","{item} kh\xf4ng c\u1ee9u n\u1ed5i ng\u01b0\u01a1i \u0111\xe2u.","Ng\u01b0\u01a1i b\u1eaft \u0111\u1ea7u ph\u1ea3i d\u1ef1a v\xe0o {item} r\u1ed3i sao?","{item} c\u0169ng kh\xf4ng gi\xfap g\xec \u0111\xe2u.","Ng\u01b0\u01a1i c\xf3 th\u1ec3 d\xf9ng {item} \u1edf \u0111\xe2u?","{item} , con ch\xf3 ch\u01a1i d\u01a1","ch\u01a1i m\xe0 ch\u01a1i item h\u1ea3 m\xe0y","{item} \xe0? H\u1ebft b\xe0i r\u1ed3i n\xean ph\u1ea3i x\xe0i \xe0?","D\xf9ng {item} xong r\u1ed3i t\xednh sao ti\u1ebfp?","{item} kh\xf4ng k\xe9o n\u1ed5i v\xe1n n\xe0y \u0111\xe2u.","Ng\u01b0\u01a1i ph\u1ea3i nh\u1edd t\u1edbi {item} r\u1ed3i \xe0?","{item} ch\u1ec9 gi\xfap ng\u01b0\u01a1i s\u1ed1ng th\xeam v\xe0i gi\xe2y.","Ui, x\xe0i lu\xf4n {item} c\u01a1 \xe0.","{item} c\u0169ng ch\u1ec9 l\xe0 gi\u1ea3i ph\xe1p t\u1ea1m th\xf4i.","T\u01b0\u1edfng {item} gh\xea l\u1eafm, h\xf3a ra c\u0169ng v\u1eady.","{item} \u0111\xf3 kh\xf4ng thay \u0111\u1ed5i \u0111\u01b0\u1ee3c k\u1ebft c\u1ee5c.","Ng\u01b0\u01a1i \u0111ang panic n\xean m\u1edbi x\xe0i {item}.","{item} c\u1ee9u \u0111\u01b0\u1ee3c ng\u01b0\u01a1i kh\xf4ng?","C\u1ed1 g\u1eafng l\u1eafm m\u1edbi b\u1eadt {item} \u0111\xfang kh\xf4ng?","{item} \u0111\xf3 \u0111\u1ec3 l\xe0m g\xec v\u1eady?","D\xf9ng {item} m\xe0 v\u1eabn run \xe0?","{item} xong r\u1ed3i v\u1eabn thua th\xf4i.","\u0110\u1ebfn m\u1ee9c ph\u1ea3i spam {item} lu\xf4n r\u1ed3i \xe0?","{item} c\u0169ng kh\xf4ng che \u0111\u01b0\u1ee3c sai l\u1ea7m \u0111\xe2u.","Ng\u01b0\u01a1i c\xe0ng d\xf9ng {item}, c\xe0ng l\u1ed9 y\u1ebfu.","{item} ch\u1ec9 l\xe0m ta th\u1ea5y ng\u01b0\u01a1i b\xed th\xf4i.","H\u1ebft chi\xeau n\xean l\xf4i {item} ra \u0111\xfang kh\xf4ng?","X\xe0i {item} cho \u0111\u1ee1 qu\xea \xe0?","{item} kh\xf4ng g\xe1nh n\u1ed5i \u0111\xe2u.","C\xf3 {item} m\xe0 \u0111\xe1nh v\u1eady \xe0?","{item} v\xe0o tay ng\u01b0\u01a1i c\u0169ng ph\xed.","\u0110\u1eebng tr\xf4ng c\u1eady v\xe0o {item} qu\xe1.","C\u1ee9 d\xf9ng {item} \u0111i, ta xem \u0111\u01b0\u1ee3c bao l\xe2u.","{item} kh\xf4ng gi\xfap ng\u01b0\u01a1i l\u1eadt k\xe8o \u0111\xe2u.","D\xf9ng {item} xong r\u1ed3i h\u1ebft ph\xe9p lu\xf4n ch\u1ee9 g\xec?","{item} ch\u1ec9 tr\xec ho\xe3n th\u1ea5t b\u1ea1i th\xf4i.","Ng\u01b0\u01a1i \u0111ang k\xe9o d\xe0i s\u1ef1 \u0111au \u0111\u1edbn b\u1eb1ng {item}.","\xc1i ch\xe0, {item} lu\xf4n c\u01a1 \xe0.","Ch\u01a1i t\u1edbi m\u1ee9c ph\u1ea3i d\xf9ng {item} r\u1ed3i.","{item} nh\xecn quen gh\xea, ch\u1eafc x\xe0i ho\xe0i.","L\u1ea1i {item} n\u1eefa \xe0?","Kh\xf4ng c\xf3 {item} ch\u1eafc ng\u01b0\u01a1i toang l\xe2u r\u1ed3i.","{item} kh\xf4ng c\u1ee9u n\u1ed5i \u0111\xe2u.","D\xf9ng th\xeam {item} c\u0169ng v\xf4 \xedch th\xf4i.","Ng\u01b0\u01a1i \u0111ang t\u1ef1 l\u1eeba m\xecnh b\u1eb1ng {item}.","{item} ch\u1ec9 l\xe0m tr\u1eadn \u0111\u1ea5u k\xe9o d\xe0i th\xeam ch\xfat.","Ng\u01b0\u01a1i \u0111ang c\u1ed1 g\u1eafng v\xf4 v\u1ecdng v\u1edbi {item}.","C\xf3 {item} m\xe0 v\u1eabn y\u1ebfu v\u1eady.","{item} kh\xf4ng l\xe0m ng\u01b0\u01a1i m\u1ea1nh h\u01a1n \u0111\xe2u.","Sai t\u1eeb g\u1ed1c r\u1ed3i, {item} kh\xf4ng s\u1eeda \u0111\u01b0\u1ee3c.","{item} kh\xf4ng ph\u1ea3i ph\xe9p m\xe0u \u0111\xe2u.","\u0110\u1eebng ngh\u0129 {item} s\u1ebd c\u1ee9u ng\u01b0\u01a1i.","D\xf9ng {item} \u0111i, r\u1ed3i ng\u01b0\u01a1i s\u1ebd hi\u1ec3u.","{item} ch\u1ec9 khi\u1ebfn k\u1ebft c\u1ee5c t\u1edbi ch\u1eadm h\u01a1n.","Ng\u01b0\u01a1i \u0111ang b\xe1m v\xedu v\xe0o {item}.","{item} l\xe0 hi v\u1ecdng cu\u1ed1i c\u1ee7a ng\u01b0\u01a1i \xe0?","Hi v\u1ecdng mong manh t\u1eeb {item} th\xf4i.","{item}? Ta ch\u1edd ng\u01b0\u01a1i d\xf9ng t\u1eeb n\xe3y gi\u1edd.","Ng\u01b0\u01a1i v\u1eeba l\xe3ng ph\xed {item}.","{item} \u0111\xf3 \u0111\xe1ng ra n\xean d\xf9ng s\u1edbm h\u01a1n.","Gi\u1edd m\u1edbi d\xf9ng {item} th\xec mu\u1ed9n r\u1ed3i.","{item} kh\xf4ng \u0111\xfang timing r\u1ed3i."],t.s)
